c_memory_scanner:
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void scan_memory(const void *start, size_t length, const char *pattern) {
    const unsigned char *p = (const unsigned char*)start;
    size_t plen = strlen(pattern);
    for (size_t i = 0; i <= length - plen; i++) {
        if (memcmp(p + i, pattern, plen) == 0) {
            printf("Found pattern at offset 0x%zx\n", i);
        }
    }
}

int main() {
    char data[] = "AAAA_SECRET_BBBB_SECRET_CCCC";
    printf("Scanning %zu bytes for pattern...\n", sizeof(data));
    scan_memory(data, sizeof(data), "SECRET");
    return 0;
}

