c_linked_list:
#include <stdio.h>
#include <stdlib.h>

typedef struct node {
    int data;
    struct node *next;
} node_t;

node_t *create_node(int data) {
    node_t *n = malloc(sizeof(node_t));
    n->data = data;
    n->next = NULL;
    return n;
}

void push(node_t **head, int data) {
    node_t *n = create_node(data);
    n->next = *head;
    *head = n;
}

void print_list(node_t *head) {
    for (node_t *p = head; p; p = p->next)
        printf("%d -> ", p->data);
    printf("NULL\n");
}

void free_list(node_t *head) {
    while (head) {
        node_t *tmp = head;
        head = head->next;
        free(tmp);
    }
}

int main() {
    node_t *list = NULL;
    for (int i = 1; i <= 5; i++) push(&list, i * 10);
    print_list(list);
    free_list(list);
    return 0;
}

c_thread_pool:
#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <unistd.h>

#define NUM_THREADS 4
#define NUM_TASKS 8

typedef struct {
    int task_id;
} task_t;

void *worker(void *arg) {
    task_t *task = (task_t*)arg;
    printf("Thread %lu processing task %d\n", pthread_self(), task->task_id);
    usleep(100000); // Simulate work
    printf("Task %d complete\n", task->task_id);
    free(task);
    return NULL;
}

int main() {
    pthread_t threads[NUM_TASKS];
    for (int i = 0; i < NUM_TASKS; i++) {
        task_t *t = malloc(sizeof(task_t));
        t->task_id = i;
        pthread_create(&threads[i], NULL, worker, t);
    }
    for (int i = 0; i < NUM_TASKS; i++)
        pthread_join(threads[i], NULL);
    printf("All tasks complete\n");
    return 0;
}

