c_xor_cipher:
#include <stdio.h>
#include <string.h>

void xor_cipher(unsigned char *data, size_t len, const unsigned char *key, size_t klen) {
    for (size_t i = 0; i < len; i++)
        data[i] ^= key[i % klen];
}

int main() {
    unsigned char msg[] = "Hello, World!";
    unsigned char key[] = "SECRET";
    size_t mlen = strlen((char*)msg);
    size_t klen = strlen((char*)key);

    printf("Original: %s\n", msg);

    xor_cipher(msg, mlen, key, klen);
    printf("Encrypted: ");
    for (size_t i = 0; i < mlen; i++) printf("%02x ", msg[i]);
    printf("\n");

    xor_cipher(msg, mlen, key, klen);
    printf("Decrypted: %s\n", msg);
    return 0;
}
